class Solution {
public:
    int maxScoreSightseeingPair(vector<int>& values) {
        int max_score = values[0] + 0;
        int max_val = values[0];
        for (int i = 1; i < values.size(); i++) {
            max_score = max(max_score, max_val + values[i] - i);
            max_val = max(max_val, values[i] + i);
        }
        return max_score;
    }
};
